const b = $input.first().json.body || $input.first().json || {};
return [{ json: {
  respostas_usuario: b.content || '',
  etp: b.etp_content || '',
  matriz_risco: b.matriz_riscos || '',
  object_nature: b.object_nature || 'Aquisição de Bens',
  process_id: b.process_id || 'N/A'
}}];

const outputRaw = $input.first().json?.output || '{}';
let texto = '';

try {
  if (typeof outputRaw === 'object' && outputRaw !== null) {
    texto = outputRaw.action_input?.text || outputRaw.output || JSON.stringify(outputRaw);
  } else {
    let clean = outputRaw.replace(/```markdown/g, '').replace(/```/g, '').trim();
    try {
      const parsed = JSON.parse(clean);
      texto = parsed.action_input ? (parsed.action_input.text || parsed.action_input) : (parsed.output || clean);
    } catch (e) {
      texto = clean;
    }
  }
} catch (e) { texto = outputRaw; }

return [{ json: { sucesso: true, bloco: 2, texto_formatado: texto } }];
